## PUTとPATCHの使い分け

```ts
// PUT: リソース全体を置き換える（べき等）
// 省略フィールドはnullや初期値になる
PUT /users/123
{
  "name": "Taka Updated",
  "email": "taka@example.com",
  "role": "admin"  // 全フィールド必須
}

// PATCH: 部分更新（送ったフィールドだけ変更）
PATCH /users/123
{
  "name": "Taka Updated"  // nameだけ変更
}
```

```ts
// NestJS での PATCH 実装
@Patch(':id')
async update(
  @Param('id') id: number,
  @Body() dto: UpdateUserDto, // すべてオプショナルなDTO
) {
  return this.usersService.update(id, dto);
}

// DTO
export class UpdateUserDto {
  @IsOptional()
  @IsString()
  name?: string;

  @IsOptional()
  @IsEmail()
  email?: string;
}
